import './Search.scss';

import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { ChangeEventHandler, KeyboardEventHandler } from 'react';
import React, { useEffect, useImperativeHandle, useRef, useState } from 'react';

import { classNames } from '../../helpers/classnames';
import { Divider } from '../Divider';
import { IconButton, type IconButtonProps } from '../IconButton';
import { Controlled } from './Controlled';
import { SearchDropdown } from './Search.dropdown';
import type { SearchDropdownProps, SearchProps } from './Search.types';
import { type ControlledSearch, iconSize } from './Search.types';

export const Search = React.forwardRef<HTMLInputElement, SearchProps>(
	(
		{
			fullWidth,
			size = 'medium',
			className,
			inputClassName,
			value,
			onSearch,
			onChange,
			onKeyUp,
			onClear,
			filterItems,
			selectedFilter,
			onFilterChange,
			dataTestId = 'Search',
			isAdaptive = false,
			maskConfig,
			...props
		},
		ref,
	) => {
		const inputRef = useRef<HTMLInputElement>(null);
		useImperativeHandle(ref, () => inputRef.current);

		const rootRef = useRef<HTMLSpanElement>(null);
		const categoriesRef = useRef<HTMLDivElement>(null);
		const [isOpen, setOpen] = useState(false);

		const handleOpen = (): void => setOpen(true);
		const handleClose = (): void => setOpen(false);

		const inputClasses = classNames('dsb_search', `dsb_search-size__${size}`, inputClassName);
		const wrapperClasses = classNames('dsb_search-wrapper', fullWidth && 'dsb_search-wrapper__full', className);

		const handleSearch = (): void => {
			onSearch?.(value);
		};

		const handleClear = (): void => {
			onSearch?.('');
			onClear?.();
			inputRef?.current.focus();
		};

		const handleChange: ChangeEventHandler<HTMLInputElement> = event => {
			onChange?.(event);
		};

		const handleKeyUp: KeyboardEventHandler<HTMLInputElement> = event => {
			if (event.key === 'Enter') {
				handleSearch();
			}
			onKeyUp?.(event);
		};

		const makeCategorySelectComponent = (): React.JSX.Element => {
			const rightIcon = (
				<IconButton
					dataTestId={dataTestId + '-arrowBut'}
					size={size}
					iconName={isOpen ? Icons.NavArrowUp : Icons.NavArrowDown}
					onClick={isOpen ? handleClose : handleOpen}
				/>
			);

			const dropdownMenuProps: SearchDropdownProps<string, HTMLSpanElement> = {
				options: filterItems || [],
				parentRef: rootRef,
				values: selectedFilter ? [selectedFilter] : [],
				onChange: ([onChangeSelectedFilter]) => {
					onFilterChange?.(onChangeSelectedFilter ?? undefined);
					setOpen(false);
				},
				makeOption: item => <span>{item.value}</span>,
				onOutsideClick: () => {
					setOpen(false);
					onClear?.();
				},
				isOpen,
				handleSetOpen: setOpen,
				multiple: false,
				dataTestId: dataTestId + '-dropdown',
			};

			const classNameLabel = classNames({
				'dsb_search_categories_label-placeholder': !selectedFilter?.value,
			});

			return (
				<div
					role="search"
					tabIndex={0}
					className="dsb_search_categories"
					ref={categoriesRef}
					onClick={handleOpen}
					onKeyDown={event => {
						if (event.key === 'Enter' || event.key === ' ') {
							event.preventDefault();
							handleOpen();
						}
					}}
					data-testid={dataTestId + '-categories'}
				>
					<Divider className="dsb_search_categories_vertical-divider" />
					<span className={classNameLabel} data-testid={dataTestId + '-selectedFilter'}>
						{selectedFilter?.value || 'Категории'}
					</span>
					{rightIcon}
					{isOpen && <SearchDropdown {...dropdownMenuProps} />}
				</div>
			);
		};

		const [leftCategory, setLeftCategory] = useState(categoriesRef?.current?.clientWidth || 0);
		useEffect(() => {
			setLeftCategory(categoriesRef?.current?.clientWidth || 0);
		}, [categoriesRef, selectedFilter]);
		const rightCloseButton = leftCategory ? leftCategory + 16 : 16;

		const dataTestInputId = `${dataTestId}-input`;
		const dataTestIconId = `${dataTestId}-butClose`;

		const inputProps: ControlledSearch = {
			onKeyUp: handleKeyUp,
			onChange: handleChange,
			className: inputClasses,
			autoComplete: 'off',
			type: 'search',
			style: {
				paddingRight: `${leftCategory ? leftCategory + 52 : 52}px`,
			},
			...props,
		};

		const iconButtonProps: IconButtonProps = {
			iconName: Icons.Close,
			className: 'dsb_search-close-button',
			style: { right: `${rightCloseButton}px` },
			size: iconSize[size],
			onClick: handleClear,
		};

		return (
			<span data-testid={dataTestId} className={wrapperClasses} ref={rootRef}>
				<IconButton
					iconName={Icons.Search}
					className="dsb_search-button"
					size={iconSize[size]}
					onClick={handleSearch}
					dataTestId={dataTestId + '-butSearch'}
				/>

				{value === undefined ? (
					<Controlled
						inputRef={inputRef}
						dataTestId={dataTestInputId}
						dataTestIconId={dataTestIconId}
						iconButton={iconButtonProps}
						{...inputProps}
					/>
				) : (
					<>
						<input ref={inputRef} value={value} data-testid={dataTestInputId} {...inputProps} />
						{value && <IconButton {...iconButtonProps} dataTestId={dataTestIconId} />}
					</>
				)}

				{filterItems && makeCategorySelectComponent()}
			</span>
		);
	},
);
